const express = require('express');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey(process.env.SENDGRID_API_KEY || 'SG.test_key_abc123');

const app = express();
app.use(express.json({ limit: '1mb' }));

async function sendEmailNotification({
  to,
  subject,
  text,
  html,
  from = 'devops-internal@example.com',
  replyTo
}) {
  if (!to) throw new Error('Missing "to"');
  if (!subject) throw new Error('Missing "subject"');
  if (!text && !html) throw new Error('Missing "text" or "html"');

  const msg = {
    to,
    from,
    subject,
    text: text || undefined,
    html: html || undefined,
    replyTo: replyTo || undefined
  };

  return sgMail.send(msg);
}

app.post('/notify-email', async (req, res) => {
  try {
    const {
      to,
      subject,
      text,
      html,
      from,
      replyTo
    } = req.body || {};

    const result = await sendEmailNotification({ to, subject, text, html, from, replyTo });

    const response = Array.isArray(result) ? result[0] : result;
    res.status(200).json({
      ok: true,
      statusCode: response && response.statusCode ? response.statusCode : 202
    });
  } catch (err) {
    res.status(500).json({
      ok: false,
      error: err && err.message ? err.message : 'Failed to send email'
    });
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Email notifier listening on http://localhost:${port}`);
});

module.exports = { app, sendEmailNotification };